import axios from 'axios'
import store from '../store'

const http = axios.create({
  baseURL: '/api',
  timeout: 10000
})

http.interceptors.request.use(config => {
  const token = store.state.auth.token
  if (token) {
    config.headers = config.headers || {}
    config.headers['Authorization'] = `Bearer ${token}`
  }
  return config
})

http.interceptors.response.use(
  resp => resp,
  async error => {
    if (error.response && error.response.status === 401) {
      const rt = store.state.auth.refreshToken
      if (rt) {
        try {
          const r = await axios.post('/api/auth/refresh', null, { params: { refreshToken: rt } })
          store.commit('auth/setAuth', { token: r.data.accessToken, refreshToken: rt, user: store.state.auth.user })
          error.config.headers['Authorization'] = `Bearer ${r.data.accessToken}`
          return http.request(error.config)
        } catch (e) {
          store.commit('auth/logout')
          location.href = '/login'
        }
      } else {
        store.commit('auth/logout')
        location.href = '/login'
      }
    }
    return Promise.reject(error)
  }
)

export default http
